"""
Observer: verify winrapids-scan generated kernel source compiles via NVRTC
and produces correct results for AddOp (cumulative sum).

Tests:
1. NVRTC compilation (does the generated CUDA code compile?)
2. Correctness against CuPy cumsum
3. Single-block limitation check (what happens beyond blockDim.x?)
"""
import cupy as cp
import numpy as np
import time

# This is the EXACT kernel source that winrapids-scan generates for AddOp.
# Copied from `cargo run --bin scan-test` output (verified via lib.rs + engine.rs).
ADD_KERNEL = r"""
// Auto-generated scan kernel for operator: add
// Liftability: associative operator -> O(log n) parallel scan
// Generated by winrapids-scan (Rust)

typedef double state_t;

__device__ __forceinline__ state_t make_identity() {
    state_t id = 0.0;
    return id;
}

__device__ __forceinline__ state_t lift_element(double x) {
    state_t s = x;
    return s;
}

__device__ __forceinline__ state_t combine_states(state_t a, state_t b) {
    state_t result = (a + b);
    return result;
}

__device__ __forceinline__ double extract_primary(state_t s) {
    return s;
}

// Inclusive scan: each block processes blockDim.x elements.
// Shared memory stores state_t per thread.
extern "C" __global__ void scan_inclusive(
    const double* __restrict__ input,
    double* __restrict__ output,
    int n
) {
    extern __shared__ char shared_raw[];
    state_t* shared = (state_t*)shared_raw;

    int tid = threadIdx.x;
    int gid = blockIdx.x * blockDim.x + tid;

    // Load: lift each element into state space
    shared[tid] = (gid < n) ? lift_element(input[gid]) : make_identity();
    __syncthreads();

    // Up-sweep (reduce phase)
    for (int stride = 1; stride < blockDim.x; stride *= 2) {
        int idx = (tid + 1) * stride * 2 - 1;
        if (idx < blockDim.x) {
            shared[idx] = combine_states(shared[idx - stride], shared[idx]);
        }
        __syncthreads();
    }

    // Down-sweep (distribute phase)
    for (int stride = blockDim.x / 4; stride > 0; stride /= 2) {
        int idx = (tid + 1) * stride * 2 - 1;
        if (idx + stride < blockDim.x) {
            shared[idx + stride] = combine_states(shared[idx], shared[idx + stride]);
        }
        __syncthreads();
    }

    // Extract and write output
    if (gid < n) {
        output[gid] = extract_primary(shared[tid]);
    }
}
"""


def main():
    print("=" * 70)
    print("Observer: Kernel Compilation + Correctness Verification")
    print("=" * 70)

    # -- Test 1: NVRTC Compilation --
    print("\n-- Test 1: NVRTC Compilation --\n")

    t0 = time.perf_counter()
    try:
        module = cp.RawModule(code=ADD_KERNEL, options=('--std=c++17',))
        kernel = module.get_function('scan_inclusive')
        t1 = time.perf_counter()
        print(f"  NVRTC compile + load: {(t1-t0)*1000:.1f} ms  PASS")
    except Exception as e:
        print(f"  NVRTC FAILED: {e}")
        return

    # -- Test 2: Correctness (single block, n <= 256) --
    print("\n-- Test 2: Correctness (single block) --\n")

    for n in [8, 16, 32, 64, 128, 256]:
        rng = np.random.default_rng(42)
        data = rng.standard_normal(n).astype(np.float64)

        d_input = cp.asarray(data)
        d_output = cp.zeros(n, dtype=cp.float64)

        block_size = n
        shared_mem = n * 8  # sizeof(double)

        kernel((1,), (block_size,), (d_input, d_output, n), shared_mem=shared_mem)
        cp.cuda.Stream.null.synchronize()

        result = cp.asnumpy(d_output)
        reference = np.cumsum(data)
        max_err = np.max(np.abs(result - reference))

        status = "PASS" if max_err < 1e-10 else "FAIL"
        print(f"  n={n:>4}: max_err={max_err:.2e}  {status}")

    # -- Test 3: Multi-block limitation --
    print("\n-- Test 3: Multi-block behavior (n > block_size) --\n")

    BLOCK = 256
    for n in [257, 512, 1024]:
        rng = np.random.default_rng(42)
        data = rng.standard_normal(n).astype(np.float64)

        d_input = cp.asarray(data)
        d_output = cp.zeros(n, dtype=cp.float64)

        n_blocks = (n + BLOCK - 1) // BLOCK
        shared_mem = BLOCK * 8

        kernel((n_blocks,), (BLOCK,), (d_input, d_output, n), shared_mem=shared_mem)
        cp.cuda.Stream.null.synchronize()

        result = cp.asnumpy(d_output)
        reference = np.cumsum(data)

        # Check first block (should be correct)
        first_block_err = np.max(np.abs(result[:BLOCK] - reference[:BLOCK]))

        # Check full array (will be WRONG without block-level prefix pass)
        full_err = np.max(np.abs(result - reference))

        # Check if blocks are scanned independently
        block_2_ref = np.cumsum(data[BLOCK:2*BLOCK]) if n > BLOCK else None
        block_2_err = np.max(np.abs(result[BLOCK:2*BLOCK] - block_2_ref)) if block_2_ref is not None else 0

        print(f"  n={n:>4} ({n_blocks} blocks):")
        print(f"    First block error: {first_block_err:.2e}  {'PASS' if first_block_err < 1e-10 else 'FAIL'}")
        print(f"    Full array error:  {full_err:.2e}  {'EXPECTED FAIL (no block prefix pass)' if full_err > 1e-6 else 'PASS'}")
        print(f"    Block 2 independent scan: {block_2_err:.2e}  {'CONFIRMS blocks are independent' if block_2_err < 1e-10 else 'UNEXPECTED'}")

    # -- Test 4: Launch overhead measurement --
    print("\n-- Test 4: Kernel launch overhead (n=256, single block) --\n")

    d_input = cp.random.randn(256).astype(cp.float64)
    d_output = cp.zeros(256, dtype=cp.float64)

    # Warmup
    for _ in range(5):
        kernel((1,), (256,), (d_input, d_output, 256), shared_mem=256*8)
    cp.cuda.Stream.null.synchronize()

    # Timed
    times = []
    for _ in range(20):
        cp.cuda.Stream.null.synchronize()
        t0 = time.perf_counter_ns()
        kernel((1,), (256,), (d_input, d_output, 256), shared_mem=256*8)
        cp.cuda.Stream.null.synchronize()
        t1 = time.perf_counter_ns()
        times.append((t1 - t0) / 1000)

    times.sort()
    p50 = times[len(times) // 2]
    p99 = times[-1]
    print(f"  CuPy RawKernel launch: p50={p50:.1f} us  p99={p99:.1f} us")
    print(f"  (This is CuPy's dispatch, not Rust's. E09 measured 9 us from cudarc.)")

    print(f"\n{'=' * 70}")
    print("Verification complete.")
    print("=" * 70)


if __name__ == "__main__":
    main()
